    ("link to <a href=\"../../Feeder/feeding-subassembly/#gallery\">Feeding subassembly</a> gallery for photo-backed clarity.", ("链接至 <a href=\"../../Feeder/feeding-subassembly/#gallery\">进料子组件</a> 图示以配合照片说明。", "link para galeria <a href=\"../../Feeder/feeding-subassembly/#gallery\">Subconjunto de alimentação</a> para clareza com fotos.")),
    ("link to <a href=\"../Feeder/feeding-subassembly/index.html#gallery\">Feeding subassembly</a> gallery for photo-backed clarity.", ("链接至 <a href=\"../Feeder/feeding-subassembly/index.html#gallery\">进料子组件</a> 图示以配合照片说明。", "link para galeria <a href=\"../Feeder/feeding-subassembly/index.html#gallery\">Subconjunto de alimentação</a> para clareza com fotos.")),
