def get_content_with_hrefs(lang: str) -> list[tuple[str, str]]:
    """Translations that include <a href= - must be applied BEFORE URL protection."""
    idx = 0 if lang == "zh" else 1
    pairs = [(en, t[idx]) for en, t in TRANSLATIONS_CONTENT if "<a href=" in en or 'href="' in en]
    pairs.sort(key=lambda p: -len(p[0]))
    return pairs
